const now = new Date();
const dayOfWeek = now.getDay();
const daysToLastMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() - daysToLastMonday - 7);
lastMonday.setHours(0, 0, 0, 0);

const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);
lastSunday.setHours(23, 59, 59, 0);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    week_start: fmt(lastMonday),
    week_end:   fmt(lastSunday),
    week_label: `Week of ${fmt(lastMonday)} to ${fmt(lastSunday)}`
  }
}];

const allCurrent = $('AWIN — Get All Current Publishers').all()
  .flatMap(p => Array.isArray(p.json) ? p.json : [p.json])
  .map(p => ({
    id:            String(p.id),
    name:          p.name,
    primaryRegion: p.primaryRegion,
    primaryType:   p.primaryType
  }));

const knownIds = new Set(
  $('Read Known Publisher IDs from Master Tab').all()
    .map(r => String(r.json.publisher_id))
);

const newPublishers = allCurrent.filter(p => !knownIds.has(p.id));

const staticData = $getWorkflowStaticData('global');
staticData.newPublishersThisWeek = newPublishers.length;

return newPublishers.length > 0
  ? newPublishers.map(p => ({ json: { ...p, detected_as: 'new_this_week' } }))
  : [{ json: { no_new_publishers: true } }];

const html = $json.data || $json.body || '';

const emailMatch = html.match(/href=["']mailto:([^"']+)["']/i);
const email = emailMatch ? emailMatch[1].trim().toLowerCase() : null;

const phoneMatch = html.match(/(?:tel:|phone|mobile|contact)[\s\S]{0,50}?([\+\d][\d\s\-\(\)]{6,20})/i);
const phone = phoneMatch ? phoneMatch[1].replace(/\s+/g, '').trim() : null;

const nameMatch = html.match(/(?:contact(?:\s+name)?|account\s+manager|fn)[\s\S]{0,100}?<[^>]+>\s*([A-Z][a-z]+ [A-Z][a-z]+)/i);
const contactName = nameMatch ? nameMatch[1].trim() : null;

const websiteMatch = html.match(/(?:website|primary\s*url|promotional\s*url)[\s\S]{0,200}?href=["'](https?:\/\/[^"']+)["']/i);
const website = websiteMatch ? websiteMatch[1].trim() : null;

const contactHidden = /contact.*hidden|privacy.*setting|not\s+publicly/i.test(html);

const weekStart = $('Generate Last Week Date Range').item.json.week_start;

return [{
  json: {
    ...$json,
    scraped_email:        email,
    scraped_phone:        phone,
    scraped_contact_name: contactName,
    scraped_website:      website,
    contact_hidden:       contactHidden,
    profile_scraped:      true,
    join_date:            weekStart,
    detected_as:          'new_this_week'
  }
}];

const raw = $json.scraped_website || $json.primaryUrl || $json.displayUrl || '';

const domain = raw
  .replace(/https?:\/\//i, '')
  .replace(/^www\./i, '')
  .split('/')[0]
  .split('?')[0]
  .trim()
  .toLowerCase();

const isValid = domain.length > 3 && domain.includes('.');

return [{ json: { ...$json, domain: isValid ? domain : null, domain_valid: isValid } }];

const data = $json.data || {};
const emails = data.emails || [];

const best = emails
  .filter(e => (e.confidence || 0) >= 70)
  .sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0] || emails[0] || {};

return [{
  json: {
    ...$json,
    hunter_email:       best.value || null,
    hunter_first_name:  best.first_name || null,
    hunter_last_name:   best.last_name || null,
    hunter_confidence:  best.confidence || null,
    hunter_email_type:  best.type || null,
    hunter_org:         data.organization || null,
    hunter_phone:       data.phone_number || null
  }
}];

const staticData = $getWorkflowStaticData('global');
staticData.hunterCallsThisMonth = (staticData.hunterCallsThisMonth || 0) + 1;
return [{ json: { ...$json, hunter_total_calls: staticData.hunterCallsThisMonth } }];

const weekData = $input.all();
const week_start = $('Generate Last Week Date Range').item.json.week_start;
const week_end   = $('Generate Last Week Date Range').item.json.week_end;

const staticData = $getWorkflowStaticData('global');
staticData.zeroActivityCount  = 0;
staticData.lowPerformersCount = 0;

return weekData.flatMap(p => {
  const rows = Array.isArray(p.json) ? p.json : [p.json];
  return rows.map(d => {
    const clicks      = d.clicks || 0;
    const hasActivity = clicks > 0 || (d.totalNo || 0) > 0;

    if (!hasActivity) staticData.zeroActivityCount++;
    if (clicks < ($vars.LOW_CLICK_THRESHOLD || 100)) staticData.lowPerformersCount++;

    return {
      json: {
        week_start,
        week_end,
        publisher_id:         d.publisherId,
        publisher_name:       d.publisherName,
        clicks,
        impressions:          d.impressions || 0,
        transactions:         d.totalNo || 0,
        confirmed_sales:      d.confirmedNo || 0,
        confirmed_value:      d.confirmedValue || 0,
        confirmed_commission: d.confirmedComm || 0,
        pending_sales:        d.pendingNo || 0,
        pending_value:        d.pendingValue || 0,
        declined_sales:       d.declinedNo || 0,
        total_commission:     d.totalComm || 0,
        has_activity:         hasActivity,
        date_recorded:        new Date().toISOString().split('T')[0]
      }
    };
  });
});

const allWeekData = $('Build Weekly Sales Records').all();
const zeroActivity = allWeekData
  .filter(p => p.json && p.json.has_activity === false);
return zeroActivity.map(p => ({ json: p.json }));

const zeroThisWeek = $('Filter Publishers With Zero Activity').all()
  .map(p => ({ id: String(p.json.publisher_id), name: p.json.publisher_name }));

const existingLog = $('Read Existing Zero Activity Log').all()
  .reduce((acc, r) => {
    const id = String(r.json.publisher_id || '');
    const wk = parseInt(r.json.weeks_inactive) || 0;
    if (id) acc[id] = Math.max(acc[id] || 0, wk);
    return acc;
  }, {});

const THRESHOLD = $vars.ZERO_ACTIVITY_THRESHOLD || 2;

return zeroThisWeek.map(p => {
  const weeksInactive = (existingLog[p.id] || 0) + 1;
  return {
    json: {
      publisher_id:    p.id,
      publisher_name:  p.name,
      weeks_inactive:  weeksInactive,
      flag_for_review: weeksInactive >= THRESHOLD,
      date_flagged:    new Date().toISOString().split('T')[0]
    }
  };
});

const weeklyData = $('Build Weekly Sales Records').all();
const THRESHOLD = $vars.LOW_CLICK_THRESHOLD || 100;

const lowPerformers = weeklyData.filter(p => {
  const clicks = p.json.clicks || 0;
  const isNewThisWeek = p.json.detected_as === 'new_this_week';
  return !isNewThisWeek && clicks < THRESHOLD;
});

return lowPerformers.map(p => ({ json: p.json }));

const contacts = $('Read Publisher Emails from Master Tab').all()
  .reduce((acc, r) => {
    acc[String(r.json.publisher_id)] = {
      email:        r.json.email || null,
      contact_name: r.json.contact_name || null
    };
    return acc;
  }, {});

const d = $json;
const match = contacts[String(d.publisher_id)] || {};

return [{
  json: {
    ...d,
    contact_email: match.email || null,
    contact_name:  match.contact_name || 'Affiliate Partner',
    has_email:     !!match.email
  }
}];

const log = $('Read Low Performance Log for Dedup Check').all();
const thisWeekStart   = $json.week_start;
const thisPublisherId = String($json.publisher_id);

const alreadySent = log.some(r =>
  String(r.json.publisher_id) === thisPublisherId &&
  r.json.week_start === thisWeekStart &&
  (r.json.email_sent === true || r.json.email_sent === 'TRUE' || r.json.email_sent === 'true')
);

return [{ json: { ...$json, already_emailed: alreadySent } }];

const staticData = $getWorkflowStaticData('global');
const attempt = staticData.retryAttempt || 1;
const baseDelay = 3000;
const maxDelay = 60000;
const jitter = Math.random() * 1000;
const delay = Math.min(baseDelay * Math.pow(2, attempt - 1) + jitter, maxDelay);
staticData.retryAttempt = attempt + 1;
return [{ json: { ...$json, delay_ms: Math.round(delay), attempt } }];
